import{_ as i,o as l,c as a,ag as s}from"./chunks/framework.CvgP6Fyv.js";const o="/bima/web-page-light.svg",n="/bima/web-page-dark.svg",r="/bima/shopping-light.svg",e="/bima/shopping-dark.svg",c="/bima/mail-light.svg",g="/bima/mail-dark.svg",h="/bima/wechat-light.svg",d="/bima/wechat-dark.svg",A=JSON.parse('{"title":"关于我们","description":"","frontmatter":{},"headers":[{"level":1,"title":"关于我们","slug":"关于我们","link":"#关于我们","children":[{"level":2,"title":"我们的理念","slug":"我们的理念","link":"#我们的理念","children":[]},{"level":2,"title":"技术能力","slug":"技术能力","link":"#技术能力","children":[]},{"level":2,"title":"业务服务","slug":"业务服务","link":"#业务服务","children":[{"level":3,"title":"CAS 单点登录系统","slug":"cas-单点登录系统","link":"#cas-单点登录系统","children":[]},{"level":3,"title":"智能中间件集成验证脚手架","slug":"智能中间件集成验证脚手架","link":"#智能中间件集成验证脚手架","children":[]},{"level":3,"title":"技术咨询服务","slug":"技术咨询服务","link":"#技术咨询服务","children":[]}]},{"level":2,"title":"联系我们","slug":"联系我们","link":"#联系我们","children":[]}]}],"relativePath":"bima/关于我们.md","filePath":"bima/关于我们.md"}'),p={name:"bima/关于我们.md"};function u(m,t,b,v,_,k){return l(),a("div",null,[...t[0]||(t[0]=[s('<h1 id="关于我们" tabindex="-1">关于我们 <a class="header-anchor" href="#关于我们" aria-label="Permalink to &quot;关于我们&quot;">​</a></h1><p>北京必码科技工作室（简称：必码），专注于开源项目定制开发与技术服务。我们秉承&quot;只写必要的代码&quot;的核心理念，致力于为客户提供轻量化、贴合业务需求的技术解决方案，让开源技术真正为业务创造价值。</p><h2 id="我们的理念" tabindex="-1">我们的理念 <a class="header-anchor" href="#我们的理念" aria-label="Permalink to &quot;我们的理念&quot;">​</a></h2><p>必码坚持&quot;小而精、专而深&quot;的服务原则，聚焦开源生态，专注技术落地。我们深知企业在使用开源产品时面临的&quot;适配难、定制难&quot;痛点，凭借丰富的开源开发经验，从需求分析到交付运维，全程细致跟进，力求让客户以最小的成本解决最实际的问题。</p><h2 id="技术能力" tabindex="-1">技术能力 <a class="header-anchor" href="#技术能力" aria-label="Permalink to &quot;技术能力&quot;">​</a></h2><p>我们拥有丰富的开源技术栈和项目经验，主要涵盖以下领域：</p><ul><li><strong>身份认证与授权</strong>：基于 CAS 的单点登录系统定制开发</li><li><strong>微服务架构</strong>：Spring Boot、Dubbo、Spring Cloud 等微服务框架集成</li><li><strong>中间件集成</strong>：Elasticsearch、Kafka、MongoDB、RabbitMQ、Redis、RocketMQ 等</li><li><strong>AI 能力集成</strong>：Ollama 本地模型和 OpenAI API 调用</li><li><strong>容器化部署</strong>：Docker、Kubernetes 等容器技术应用</li></ul><h2 id="业务服务" tabindex="-1">业务服务 <a class="header-anchor" href="#业务服务" aria-label="Permalink to &quot;业务服务&quot;">​</a></h2><h3 id="cas-单点登录系统" tabindex="-1">CAS 单点登录系统 <a class="header-anchor" href="#cas-单点登录系统" aria-label="Permalink to &quot;CAS 单点登录系统&quot;">​</a></h3><p>基于 Apereo 基金会维护的 CAS（中央认证服务）项目，提供轻量化定制开发，解决企业多系统单点登录问题。我们基于不同版本的 CAS Overlay 进行了定制化开发，提供了完整的开发基座、配置模板和部署方案。</p><p><strong>主要特性：</strong></p><blockquote><ul><li><strong>架构转型</strong>：从传统 WAR 包架构升级为现代 JAR 包架构</li><li><strong>自定义认证</strong>：实现灵活的身份验证逻辑</li><li><strong>安全加固</strong>：关闭 CAS 默认账号密码登录，提升系统安全性</li><li><strong>数据库集成</strong>：集成 MyBatis 数据库访问框架</li><li><strong>资源提取</strong>：全量提取前端静态资源和模板，方便定制</li><li><strong>多语言支持</strong>：内置中文、英文等多语言支持</li><li><strong>OAuth 2.0 支持</strong>：完整实现标准 OAuth 2.0 认证流程</li></ul></blockquote><p><strong>版本选择：</strong></p><ul><li>7.3.x 系列</li><li>6.6.x 系列</li><li>5.3.x 系列</li></ul><h3 id="智能中间件集成验证脚手架" tabindex="-1">智能中间件集成验证脚手架 <a class="header-anchor" href="#智能中间件集成验证脚手架" aria-label="Permalink to &quot;智能中间件集成验证脚手架&quot;">​</a></h3><p>面向开发者打造的一站式微服务项目脚手架，深度融合 AI 能力与主流中间件集成方案，支持开发者快速完成各类常用中间件服务的集成、验证与测试，大幅提升开发效率。</p><p><strong>主要特性：</strong></p><blockquote><ul><li><strong>AI接口能力</strong>：可调用Ollama本地模型和OpenAI API</li><li><strong>多中间件集成</strong>：集成了Elasticsearch、Kafka、MongoDB、MyBatis、RabbitMQ、Redis、RocketMQ等常用中间件</li><li><strong>统一Web界面</strong>：基于LayUI框架的直观Web界面</li><li><strong>多数据源支持</strong>：内置多数据源配置</li><li><strong>OAuth2.0客户端</strong>：集成OAuth2客户端认证机制</li></ul></blockquote><p><strong>版本选择：</strong></p><ul><li>Spring Boot 版本</li><li>Dubbo 版本</li><li>Spring Cloud 版本</li></ul><h3 id="技术咨询服务" tabindex="-1">技术咨询服务 <a class="header-anchor" href="#技术咨询服务" aria-label="Permalink to &quot;技术咨询服务&quot;">​</a></h3><p>提供专业的开源技术咨询服务，帮助企业制定合理的技术路线，解决技术难题，提升系统架构的可靠性和可扩展性。</p><blockquote><ul><li><strong>架构设计</strong>：提供系统架构优化建议</li><li><strong>技术指导</strong>：分享开源项目最佳实践</li><li><strong>安全评估</strong>：识别和解决潜在安全风险</li><li><strong>性能调优</strong>：提升系统性能和用户体验</li></ul></blockquote><h2 id="联系我们" tabindex="-1">联系我们 <a class="header-anchor" href="#联系我们" aria-label="Permalink to &quot;联系我们&quot;">​</a></h2><p>必码科技期待与您合作，以技术为桥，共创价值！</p><div class="contact-info"><div class="contact-item"><img src="'+o+'" class="vp-light-only" width="24" height="24"><img src="'+n+'" class="vp-dark-only" width="24" height="24"><span>官方网址：https://bima.cc</span></div></div><div class="contact-info"><div class="contact-item"><img src="'+r+'" class="vp-light-only" width="24" height="24"><img src="'+e+'" class="vp-dark-only" width="24" height="24"><span>官方店铺：https://bima.taobao.com</span></div></div><div class="contact-info"><div class="contact-item"><img src="'+c+'" class="vp-light-only" width="24" height="24"><img src="'+g+'" class="vp-dark-only" width="24" height="24"><span>联系邮箱：bima.cc@qq.com</span></div></div><div class="contact-info"><div class="contact-item"><img src="'+h+'" class="vp-light-only" width="24" height="24"><img src="'+d+'" class="vp-dark-only" width="24" height="24"><span>联系微信：e18929958</span></div></div>',29)])])}const f=i(p,[["render",u]]);export{A as __pageData,f as default};
